package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.google.common.collect.ImmutableMap;
import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.collect.tuple.Triple;
import com.opengamma.strata.market.curve.CurveInfoType;
import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCds;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche based on ISDA standard model.
 * <p>
 * The CDS tranche is priced by computing the expected loss between the attachment and detachment points
 * using the underlying CDS index credit curve.
 * <p>
 * {@code CreditRatesProvider} must contain the index credit curve as well as
 * the information on the relevant recovery rate and index factor.
 * <p>
 * This pricer invokes the implementation in {@link IsdaCdsProductPricer}.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for single name CDS.
   */
  private final IsdaCdsProductPricer underlyingPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.underlyingPricer = new IsdaCdsProductPricer(formula);
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return underlyingPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the price of the CDS tranche product, which is the minus of the present value per unit notional.
   * <p>
   * This method can calculate the clean or dirty price, see {@link PriceType}.
   * If calculating the clean price, the accrued interest is calculated based on the step-in date.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCds underlyingCds = cdsTranche.getUnderlyingIndex().toSingleNameCds();
    return underlyingPricer.price(underlyingCds, ratesProvider, referenceDate, priceType, refData);
  }

  /**
   * Calculates the price sensitivity of the product.
   * <p>
   * The price sensitivity of the product is the sensitivity of price to the underlying curves.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder priceSensitivity(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ResolvedCds underlyingCds = cdsTranche.getUnderlyingIndex().toSingleNameCds();
    return underlyingPricer.priceSensitivity(underlyingCds, ratesProvider, referenceDate, refData);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche product.
   * <p>
   * The present value of the product is based on {@code referenceDate}.
   * This is typically the valuation date, or cash settlement date if the product is associated with a {@code Trade}.
   * <p>
   * This method can calculate the clean or dirty present value, see {@link PriceType}.
   * If calculating the clean value, the accrued interest is calculated based on the step-in date.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    if (isExpired(cdsTranche, ratesProvider)) {
      return CurrencyAmount.of(cdsTranche.getCurrency(), 0d);
    }
    ResolvedCds underlyingCds = cdsTranche.getUnderlyingIndex().toSingleNameCds();
    LocalDate stepinDate = cdsTranche.getStepinDateOffset().adjust(ratesProvider.getValuationDate(), refData);
    LocalDate effectiveStartDate = underlyingCds.calculateEffectiveStartDate(stepinDate);
    double recoveryRate = underlyingPricer.recoveryRate(underlyingCds, ratesProvider);
    Triple<CreditDiscountFactors, LegalEntitySurvivalProbabilities, Double> rates =
        reduceDiscountFactors(underlyingCds, ratesProvider);

    // Compute protection leg for the full CDS
    double protectionLegFull = (1d - recoveryRate) *
        underlyingPricer.protectionFull(underlyingCds, rates.getFirst(), rates.getSecond(),
            referenceDate, effectiveStartDate);

    // For a tranche, we scale the protection leg by the spread of the tranche
    // This represents the expected loss between attachment and detachment points
    double trancheSpread = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();
    double protectionLeg = protectionLegFull * trancheSpread;

    // Compute risky annuity (RPV01)
    double rpv01 = underlyingPricer.riskyAnnuity(
        underlyingCds, rates.getFirst(), rates.getSecond(),
        referenceDate, stepinDate, effectiveStartDate, priceType);

    // Scale notional to reflect the tranche size
    double notional = cdsTranche.getNotional();
    double amount = cdsTranche.getBuySell().normalize(notional) * rates.getThird() *
        (protectionLeg - rpv01 * cdsTranche.getFixedRate());
    return CurrencyAmount.of(cdsTranche.getCurrency(), amount);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value sensitivity of the product.
   * <p>
   * The present value sensitivity of the product is the sensitivity of the present value to the underlying curves.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder presentValueSensitivity(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    if (isExpired(cdsTranche, ratesProvider)) {
      return PointSensitivityBuilder.none();
    }
    ResolvedCds underlyingCds = cdsTranche.getUnderlyingIndex().toSingleNameCds();
    return underlyingPricer.presentValueSensitivity(underlyingCds, ratesProvider, referenceDate, refData);
  }

  //-------------------------------------------------------------------------
  private boolean isExpired(ResolvedCdsTranche cdsTranche, CreditRatesProvider ratesProvider) {
    return ratesProvider.getValuationDate().isAfter(cdsTranche.getProtectionEndDate());
  }

  private Triple<CreditDiscountFactors, LegalEntitySurvivalProbabilities, Double> reduceDiscountFactors(
      ResolvedCds cds,
      CreditRatesProvider ratesProvider) {
    return underlyingPricer.reduceDiscountFactors(cds, ratesProvider);
  }

}

