package com.opengamma.strata.measure.credit;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.basics.currency.MultiCurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.data.scenario.CurrencyScenarioArray;
import com.opengamma.strata.data.scenario.DoubleScenarioArray;
import com.opengamma.strata.data.scenario.MultiCurrencyScenarioArray;
import com.opengamma.strata.data.scenario.ScenarioArray;
import com.opengamma.strata.market.param.CurrencyParameterSensitivities;
import com.opengamma.strata.market.param.CurrencyParameterSensitivity;
import com.opengamma.strata.market.sensitivity.PointSensitivities;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.pricer.credit.AccrualOnDefaultFormula;
import com.opengamma.strata.pricer.credit.AnalyticSpreadSensitivityCalculator;
import com.opengamma.strata.pricer.credit.CdsMarketQuoteConverter;
import com.opengamma.strata.pricer.credit.CreditRatesProvider;
import com.opengamma.strata.pricer.credit.IsdaCdsTranchePricer;
import com.opengamma.strata.pricer.credit.IsdaCdsTradePricer;
import com.opengamma.strata.pricer.credit.JumpToDefault;
import com.opengamma.strata.pricer.credit.SpreadSensitivityCalculator;
import com.opengamma.strata.pricer.sensitivity.MarketQuoteSensitivityCalculator;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;
import com.opengamma.strata.product.credit.ResolvedCdsTrade;

/**
 * Multi-scenario measure calculations for CDS tranche trades.
 * <p>
 * Each method corresponds to a measure, typically calculated by one or more calls to the pricer.
 */
final class CdsTranchesMeasureCalculations {

  /**
   * Default implementation.
   */
  public static final CdsTranchesMeasureCalculations DEFAULT =
      new CdsTranchesMeasureCalculations(
          new IsdaCdsTranchePricer(AccrualOnDefaultFormula.CORRECT),
          new IsdaCdsTradePricer(AccrualOnDefaultFormula.CORRECT));

  /**
   * The market quote sensitivity calculator.
   */
  private static final MarketQuoteSensitivityCalculator MARKET_QUOTE_SENS = MarketQuoteSensitivityCalculator.DEFAULT;
  /**
   * One basis point, expressed as a {@code double}.
   */
  private static final double ONE_BASIS_POINT = 1e-4;

  /**
   * Pricer for {@link ResolvedCdsTrancheTrade}.
   */
  private final IsdaCdsTranchePricer tranchePricer;
  /**
   * Pricer for the underlying CDS trade.
   */
  private final IsdaCdsTradePricer underlyingPricer;
  /**
   * Spread sensitivity calculator.
   */
  private final SpreadSensitivityCalculator cs01Calculator;
  /**
   * Market quote converter.
   */
  private final CdsMarketQuoteConverter converter;

  /**
   * Creates an instance.
   *
   * @param tranchePricer  the pricer for {@link ResolvedCdsTrancheTrade}
   * @param underlyingPricer  the pricer for the underlying CDS trade
   */
  public CdsTranchesMeasureCalculations(
      IsdaCdsTranchePricer tranchePricer,
      IsdaCdsTradePricer underlyingPricer) {
    this.tranchePricer = ArgChecker.notNull(tranchePricer, "tranchePricer");
    this.underlyingPricer = ArgChecker.notNull(underlyingPricer, "underlyingPricer");
    this.cs01Calculator = new AnalyticSpreadSensitivityCalculator(tranchePricer.getAccrualOnDefaultFormula());
    this.converter = new CdsMarketQuoteConverter(tranchePricer.getAccrualOnDefaultFormula());
  }

  //-------------------------------------------------------------------------
  // calculates present value for all scenarios
  CurrencyScenarioArray presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> presentValue(trade, marketData.scenario(i).creditRatesProvider(), PriceType.DIRTY, refData));
  }

  // calculates present value for one scenario
  CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    return tranchePricer.presentValue(trade.getProduct(), ratesProvider,
        ratesProvider.getValuationDate(), priceType, refData);
  }

  //-------------------------------------------------------------------------
  // calculates principal for all scenarios
  CurrencyScenarioArray principal(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> principal(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates principal for one scenario
  CurrencyAmount principal(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return tranchePricer.presentValue(trade.getProduct(), ratesProvider,
        ratesProvider.getValuationDate(), PriceType.CLEAN, refData);
  }

  //-------------------------------------------------------------------------
  // calculates price for all scenarios
  DoubleScenarioArray unitPrice(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return DoubleScenarioArray.of(
        marketData.getScenarioCount(),
        i -> unitPrice(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates price for one scenario
  double unitPrice(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    double puf = tranchePricer.price(trade.getProduct(), ratesProvider,
        ratesProvider.getValuationDate(), PriceType.CLEAN, refData);
    return converter.cleanPriceFromPointsUpfront(puf);
  }

  //-------------------------------------------------------------------------
  // calculates calibrated parallel IR01 for all scenarios
  CurrencyScenarioArray ir01CalibratedParallel(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> ir01CalibratedParallel(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates calibrated parallel IR01 for one scenario
  CurrencyAmount ir01CalibratedParallel(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    CurrencyAmount pv = tranchePricer.presentValue(trade.getProduct(), ratesProvider,
        ratesProvider.getValuationDate(), PriceType.DIRTY, refData);
    CurrencyAmount pvUp = tranchePricer.presentValue(trade.getProduct(),
        ratesProvider.withIsdaCreditCurve(
            ratesProvider.isdaCreditCurve(trade.getProduct().getUnderlyingIndex().getLegalEntityIds().get(0),
                trade.getProduct().getCurrency()).withParallelShift(ONE_BASIS_POINT)),
        ratesProvider.getValuationDate(), PriceType.DIRTY, refData);
    return pv.minus(pvUp).dividedBy(ONE_BASIS_POINT);
  }

  //----------- additional measure calculations can be added here -----------

}

