/**
 * Calculates the present value of the CDS tranche product.
 * <p>
 * The present value of the product is based on {@code referenceDate}.
 * This is typically the valuation date, or cash settlement date if the product is associated with a {@code Trade}.
 * <p>
 * This method can calculate the clean or dirty present value, see {@link PriceType}.
 * If calculating the clean value, the accrued interest is calculated based on the step-in date.
 *
 * @param cdsTranche  the product
 * @param ratesProvider  the rates provider
 * @param referenceDate  the reference date
 * @param priceType  the price type
 * @param refData  the reference data
 * @return the present value
 */
public CurrencyAmount presentValue(
    ResolvedCdsTranche cdsTranche,
    CreditRatesProvider ratesProvider,
    LocalDate referenceDate,
    PriceType priceType,
    ReferenceData refData) {

  if (isExpired(cdsTranche, ratesProvider)) {
    return CurrencyAmount.of(cdsTranche.getCurrency(), 0d);
  }
  // Use the underlying index's toSingleNameCds() to get equivalent single-name CDS
  ResolvedCds underlyingCds = cdsTranche.getUnderlyingIndex().toSingleNameCds();

  // Compute PV using underlying pricer, then scale by tranche spread
  double trancheSpread = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();

  // Get the PV of the equivalent single-name CDS
  CurrencyAmount cdsValue = underlyingPricer.presentValue(underlyingCds, ratesProvider, referenceDate, priceType, refData);

  // Scale by the tranche notional spread (already embedded in cdsTranche.notional from resolution)
  // The scaled value represents the tranche's share of the portfolio loss
  double scaledAmount = cdsValue.getAmount() * trancheSpread;

  return CurrencyAmount.of(cdsTranche.getCurrency(), scaledAmount);
}

