/**
 * Calculates the present value of the CDS tranche product.
 * <p>
 * The present value of the product is based on {@code referenceDate}.
 * This is typically the valuation date, or cash settlement date if the product is associated with a {@code Trade}.
 * <p>
 * This method can calculate the clean or dirty present value, see {@link PriceType}.
 * If calculating the clean value, the accrued interest is calculated based on the step-in date.
 *
 * @param cdsTranche  the product
 * @param ratesProvider  the rates provider
 * @param referenceDate  the reference date
 * @param priceType  the price type
 * @param refData  the reference data
 * @return the present value
 */
public CurrencyAmount presentValue(
    ResolvedCdsTranche cdsTranche,
    CreditRatesProvider ratesProvider,
    LocalDate referenceDate,
    PriceType priceType,
    ReferenceData refData) {

  if (isExpired(cdsTranche, ratesProvider)) {
    return CurrencyAmount.of(cdsTranche.getCurrency(), 0d);
  }
  ResolvedCds underlyingCds = cdsTranche.getUnderlyingIndex().toSingleNameCds();
  LocalDate stepinDate = cdsTranche.getStepinDateOffset().adjust(ratesProvider.getValuationDate(), refData);
  LocalDate effectiveStartDate = underlyingCds.calculateEffectiveStartDate(stepinDate);
  double recoveryRate = underlyingPricer.recoveryRate(underlyingCds, ratesProvider);
  Triple<CreditDiscountFactors, LegalEntitySurvivalProbabilities, Double> rates = reduceDiscountFactors(underlyingCds, ratesProvider);

  // Compute protection leg for the full CDS
  double protectionLegFull = (1d - recoveryRate) *
      underlyingPricer.protectionFull(underlyingCds, rates.getFirst(), rates.getSecond(),
          referenceDate, effectiveStartDate);

  // For a tranche, we scale the protection leg by the spread of the tranche
  // This represents the expected loss between attachment and detachment points
  double trancheSpread = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();
  double protectionLeg = protectionLegFull * trancheSpread;

  // Compute risky annuity (RPV01)
  double rpv01 = underlyingPricer.riskyAnnuity(
      underlyingCds, rates.getFirst(), rates.getSecond(),
      referenceDate, stepinDate, effectiveStartDate, priceType);

  // Scale notional to reflect the tranche size
  double notional = cdsTranche.getNotional();
  double amount = cdsTranche.getBuySell().normalize(notional) * rates.getThird() *
      (protectionLeg - rpv01 * cdsTranche.getFixedRate());
  return CurrencyAmount.of(cdsTranche.getCurrency(), amount);
}

