// calculates calibrated parallel IR01 for one scenario
CurrencyAmount ir01CalibratedParallel(
    ResolvedCdsTrancheTrade trade,
    CreditRatesProvider ratesProvider,
    ReferenceData refData) {

  CurrencyAmount pv = tranchePricer.presentValue(trade.getProduct(), ratesProvider,
      ratesProvider.getValuationDate(), PriceType.DIRTY, refData);
  CurrencyAmount pvUp = tranchePricer.presentValue(trade.getProduct(),
      ratesProvider.withIsdaCreditCurve(
          ratesProvider.isdaCreditCurve(trade.getProduct().getUnderlyingIndex().getLegalEntityIds().get(0),
              trade.getProduct().getCurrency()).withParallelShift(ONE_BASIS_POINT)),
      ratesProvider.getValuationDate(), PriceType.DIRTY, refData);
  return pv.minus(pvUp).dividedBy(ONE_BASIS_POINT);
}

