        .buySell(underlyingIndex.getBuySell())
        .underlyingIndex(resolvedIndex)
        .attachmentPoint(attachmentPoint)
        .detachmentPoint(detachmentPoint)
        .protectionStart(resolvedIndex.getProtectionStart())
        .paymentOnDefault(resolvedIndex.getPaymentOnDefault())
        .paymentPeriods(paymentPeriods)
        .protectionEndDate(resolvedIndex.getProtectionEndDate())
        .settlementDateOffset(resolvedIndex.getSettlementDateOffset())
        .stepinDateOffset(resolvedIndex.getStepinDateOffset())
        .dayCount(resolvedIndex.getDayCount())
        .currency(underlyingIndex.getCurrency())
        .notional(trancheNotional)
        .fixedRate(underlyingIndex.getFixedRate())
